import {
  isValidElement,
  type AnchorHTMLAttributes,
  type PropsWithChildren,
  type ReactElement,
  type ReactNode,
  cloneElement,
} from 'react';
import { isElement } from 'react-is';

import type {
  AriaButtonProps,
  ButtonAria,
} from '../../../../buttons/button/types/button-aria.js';
import { AriaLabelingProps } from '../../../../core/types/a11y-props.js';
import type { BehaviorTrackingProps } from '../../../../core/types/behavior-tracking-props.js';
import { DataTestId } from '../../../../core/types/data-props.js';
import { StylingProps } from '../../../../core/types/styling-props.js';
import { mergeProps } from '../../../../core/utils/merge-props.js';
import { useTimeframeSelectorContext } from '../../hooks/useTimeframeSelectorContext.js';

/**
 * @public
 */
export type TimeframeSelectorCustomTriggerProps = AriaLabelingProps &
  StylingProps &
  DataTestId &
  BehaviorTrackingProps & {
    /** Elements to be displayed in the CustomTrigger. */
    children:
      | ReactNode
      | undefined
      | ((
          customTriggerProps: {
            displayValue: ReactNode;
            isInvalid: boolean;
            hint: string;
          },
          props:
            | (AriaLabelingProps &
                StylingProps &
                DataTestId &
                (Partial<ButtonAria<AnchorHTMLAttributes<HTMLButtonElement>>> &
                  AriaButtonProps))
            | null,
        ) => ReactElement);
  };

/**
 * Typeguard function that will check if a ReactNode is a TimeframeSelector.CustomTrigger
 * @internal
 */
export function isTimeframeSelectorCustomTriggerElement(
  child: ReactNode,
): child is ReactElement<TimeframeSelectorCustomTriggerProps> {
  return isElement(child) && child.type === CustomTrigger;
}

/**
 * A trigger component to customize a timeframe selector's trigger.
 * It applies all necessary props on the first and closest child,
 * which, therefore, should be an interactive element.
 * @public
 */
export const CustomTrigger = (props: TimeframeSelectorCustomTriggerProps) => {
  const { children, ...remainingProps } = props;
  const { triggerProps, displayValue, hint, showError } =
    useTimeframeSelectorContext();

  const dtComponentName = triggerProps?.['data-dt-component'];

  if (isValidElement<PropsWithChildren>(children)) {
    return cloneElement(children, {
      ...mergeProps(
        triggerProps,
        { color: showError ? 'critical' : undefined },
        remainingProps,
        children.props,
        { 'data-dt-component': dtComponentName },
      ),
    });
  }

  if (typeof children === 'function') {
    return children(
      { displayValue, isInvalid: showError, hint },
      mergeProps(triggerProps, remainingProps),
    );
  }

  return null;
};

CustomTrigger['displayName'] = 'TimeframeSelector.CustomTrigger';
